class Counter:
    def __init__(self):
        self.count = 0

    def handle_click(self, increment):
        if increment:
            self.count += 1
        else:
            self.count -= 1

    def render(self):
        return f'<div><button onclick={() => self.handle_click(True)}>Increment</button><button onclick={() => self.handle_click(False)}>Decrement</button><p>Count: {self.count}</p></div>'

